#include <iostream>
using namespace std;
class Str {
    char* data;
public:
    Str(const char* s) {
        data = new char[10];
        for (int i = 0; s[i]; i++) data[i] = s[i];
        data[strlen(s)] = '\0';
    }
    Str(const Str& other) {
        data = new char[10];
        for (int i = 0; other.data[i]; i++) data[i] = other.data[i];
        data[strlen(other.data)] = '\0';
        cout << "copy" << endl;
    }
    ~Str() { delete[] data; }
    void print() { cout << data << endl; }
};
int main() {
    Str a("hi");
    Str b = a;
    b.print();
    return 0;
}

